let x: Option<i32> = Some(5);
match x {
    Some(n) => println!("{}", n * 2),
    None => println!("nothing"),
}

let val: Option<&str> = Some("hello");
if let Some(s) = val {
    println!("{}", s);
}

trait Greet {
    fn hello(&self) -> String;
}
struct User { name: String }
impl Greet for User {
    fn hello(&self) -> String {
        format!("Hi, {}!", self.name)
    }
}
